package main

import (
	"container/heap"
)

type Item struct {
	cost         int64
	i, j         int
	remaining_k  int64
}

type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(grid [][]int64, k int64) int64 {
	m, n := len(grid), len(grid[0])
	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Item{0, 0, 0, k})
	visited := make(map[[3]int]int64)
	visited[[3]int{0, 0, int(k)}] = 0

	directions := [][2]int{{0, 1}, {1, 0}}

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(*Item)
		current_cost, i, j, remaining_k := current.cost, current.i, current.j, current.remaining_k
		if i == m-1 && j == n-1 {
			return current_cost
		}
		if val, exists := visited[[3]int{i, j, int(remaining_k)}]; exists && val < current_cost {
			continue
		}

		// Explore normal moves
		for _, dir := range directions {
			ni, nj := i+dir[0], j+dir[1]
			if ni >= 0 && ni < m && nj >= 0 && nj < n {
				new_cost := current_cost + grid[ni][nj]
				key := [3]int{ni, nj, int(remaining_k)}
				if val, exists := visited[key]; !exists || new_cost < val {
					visited[key] = new_cost
					heap.Push(&pq, &Item{new_cost, ni, nj, remaining_k})
				}
			}
		}

		// Explore teleport moves if remaining_k > 0
		if remaining_k > 0 {
			for x := 0; x < m; x++ {
				for y := 0; y < n; y++ {
					if (x != i || y != j) && grid[x][y] <= grid[i][j] {
						new_cost := current_cost
						new_k := remaining_k - 1
						key := [3]int{x, y, int(new_k)}
